def seed_filieres(session):
    if session.exec(select(Filiere)).first():
        print("Filières déjà présentes."); return
    for data in FILIERES:
        session.add(Filiere(**data))
    session.commit()
    print(f"OK {len(FILIERES)} filières insérées.")


def seed_universites(session):
    if session.exec(select(Universite)).first():
        print("Universités déjà présentes."); return
    for data in UNIVERSITES:
        session.add(Universite(**data))
    session.commit()
    print(f"OK {len(UNIVERSITES)} universités insérées.")


def seed_formations(session):
    if session.exec(select(Formation)).first():
        print("Formations déjà présentes."); return
    # Construire les index nom→id
    fil_idx = {f.nom: f.id_filiere for f in session.exec(select(Filiere)).all()}
    uni_idx = {u.nom: u.id_universite for u in session.exec(select(Universite)).all()}
    count = 0
    for data in FORMATIONS:
        fid = fil_idx.get(data["filiere_nom"])
        uid = uni_idx.get(data["universite_nom"])
        if not fid or not uid:
            continue
        session.add(Formation(
            id_filiere=fid, id_universite=uid,
            diplome=data["diplome"], frais_inscription=data["frais_inscription"],
            duree_reelle=data["duree_reelle"], places_disponibles=data["places_disponibles"],
        ))
        count += 1
    session.commit()
    print(f"OK {count} formations insérées.")


def seed_all():
    create_db_and_tables()
    with Session(engine) as session:
        seed_filieres(session)
        seed_universites(session)
        seed_formations(session)


if __name__ == "__main__":
    seed_all()
